Box = class()
Box.times = 0

function Box:ctor(config)
    self.config = config
    self.pos = VectorUtil.newVector3i(self.config.pos.x, self.config.pos.y, self.config.pos.z)
    self.isNew = false
    self.entityId = 0
end

function Box:refreshBoxItem()
    self.isNew = true
    self.times = self.times + 1
    local result = {}
    local num, poolIds = self:getRandomConfigByTimes(self.times)
    if poolIds == 0 then
        return
    end
    for index, poolId in pairs(poolIds) do
        local pool = TableUtil.copyTable(BoxItemConfig:getPoolById(poolId))
        if pool == nil then
            return
        end
        local tmp = RandomUtil:randomItemByWeight(tonumber(num[index]), pool, false)
        self:addTableItem(result, tmp)
    end
    if self.entityId ~= 0 then
        EngineWorld:removeEntity(self.entityId)
    end
    if result == nil then
        return
    end
    self.items = result
    local event = EventTriggerConfig:getEventByEventIdAndTimes("90016", self.times + 1)
    if not event then
        return
    end
    local pos = VectorUtil.newVector3(self.pos.x + 0.5, self.pos.y + 1, self.pos.z + 0.5)
    self.entityId = EngineWorld:addSessionNpc(pos, 0, 105401, "g1054_kong.actor", function(entity)
        local second = event.attackTime - GameMatch:getRunningTime()
        entity:setTimeLeft(second * 1000)
        entity:setCanCollided(false)
    end)
end

function Box:getRandomConfigByTimes(times)
    local numKey = "num" .. times
    local poolKey = "pool" .. times
    return self.config[numKey] or 1, self.config[poolKey] or 0
end

function Box:setBoxItem(inv)
    inv:clearChest()
    local nextSlot = 0
    for _, item in pairs(self.items) do
        local num = math.random(item.min, item.max)
        inv:initByItem(nextSlot, item.itemId, num, 0)
        nextSlot = nextSlot + 1
    end
end

function Box:setInv(inv)
    if self.isNew == false then
        return
    end
    self:setBoxItem(inv)
    self.isNew = false
end

function Box:addTableItem(result, tmp)
    for _, item in pairs(tmp) do
        table.insert(result, item)
    end
    return result
end

return Box